    95→func (m *MetricStreamingDecoder) NextMetric() error {
    96→	if m.metricIndex >= len(m.metrics) {
    97→		return io.EOF
    98→	}
    99→
   100→	m.resetMetric()
   101→	m.mData = m.mfData[m.metrics[m.metricIndex].start:m.metrics[m.metricIndex].end]
   102→	if err := m.unmarshalWithoutLabels(m, m.mData); err != nil {
   103→		return err
   104→	}
   105→	m.metricIndex++
   106→	return nil
   107→}
